#define LIMIT -999

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

int maximum(int a, int b, int c) {
    int k;
    if (a <= b)
        k = b;
    else
        k = a;

    if (k <= c)
        return c;
    else
        return k;
}

void nw_kernel1(__global int* referrence,
                __global int* input_itemsets,
                __global int* output_itemsets,
                __local int* input_itemsets_l,
                __local int* reference_l,
                int max_cols,
                int penalty,
                int blk,
                int block_width,
                int worksize,
                int offset_r,
                int offset_c) {

    int b_index_x = get_global_id(0) / BLOCK_SIZE;

    if (b_index_x >= blk) return;

    int b_index_y = blk - 1 - b_index_x;

    int global_row_start = b_index_y * BLOCK_SIZE + 1;
    int global_col_start = b_index_x * BLOCK_SIZE + 1;

    // Load reference block
    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            int r_idx = max_cols * (global_row_start + i - 1) + (global_col_start + j - 1);
            reference_l[i * BLOCK_SIZE + j] = referrence[r_idx];
        }
    }

    // Load input block (including boundary)
    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            int r_idx = max_cols * (b_index_y * BLOCK_SIZE + i) + (b_index_x * BLOCK_SIZE + j);
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = input_itemsets[r_idx];
        }
    }

    // Compute DP block
    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            int val_diag = input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1];
            int val_left = input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty;
            int val_up = input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty;

            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum(val_diag, val_left, val_up);
        }
    }

    // Write back results
    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            int r_idx = max_cols * (global_row_start + i) + (global_col_start + j);
            input_itemsets[r_idx] = input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

